+//! GPU Auto-Switch Threshold for Adaptive Batch Sizing
+//!
+//! Automatically decides whether to use GPU or CPU based on workload size.
+//! Small batches have GPU kernel launch overhead; large batches benefit from parallelism.
+//!
+//! Pattern adapted from lanceql's GPU_THRESHOLD (100K vectors) for vector similarity.
+//!
+//! Usage:
+//!   const policy = GpuPolicy.init(allocator);
+//!   defer policy.deinit();
+//!
+//!   // Auto-select device for batch
+//!   const device = policy.selectDevice(batch_size, token_count);
+//!   switch (device) {
+//!       .gpu => // Use Metal/CUDA path
+//!       .cpu => // Use SIMD path
+//!       .npu => // Use Neural Engine
+//!   }
+
+const std = @import("std");
+const builtin = @import("builtin");
+const Allocator = std.mem.Allocator;
+
+const log = std.log.scoped(.gpu_threshold);
+
+// =============================================================================
+// Device Selection
+// =============================================================================
+
+pub const Device = enum {
+    cpu,
+    gpu,
+    npu,
+
+    pub fn name(self: Device) []const u8 {
+        return switch (self) {
+            .cpu => "CPU (SIMD)",
+            .gpu => "GPU (Metal)",
+            .npu => "NPU (ANE)",
+        };
+    }
+};
+
+// =============================================================================
+// Thresholds (tuned for Apple Silicon)
+// =============================================================================
+
+pub const Thresholds = struct {
+    /// Minimum batch size to use GPU (kernel launch overhead)
+    /// Below this, CPU SIMD is faster due to zero launch overhead
+    gpu_min_batch: usize = 8,
+
+    /// Minimum tokens for GPU to be worthwhile
+    /// Short sequences have poor GPU utilization
+    gpu_min_tokens: usize = 64,
+
+    /// Minimum elements (batch * dim) for GPU
+    /// ~100K elements is break-even point on M1/M2/M3
+    gpu_min_elements: usize = 100_000,
+
+    /// Batch size threshold for NPU (Neural Engine)
+    /// NPU excels at large, predictable batches
+    npu_min_batch: usize = 32,
+
+    /// NPU prefers power of 2 batch sizes
+    npu_prefer_pow2: bool = true,
+
+    /// Maximum batch size for CPU (memory bandwidth limit)
+    cpu_max_batch: usize = 4,
+
+    /// Enable adaptive threshold learning
+    enable_learning: bool = true,
+};
+
+// =============================================================================
+// GPU Policy with Adaptive Learning
+// =============================================================================
+
+pub const GpuPolicy = struct {
+    allocator: Allocator,
+    thresholds: Thresholds,
+
+    // Adaptive learning state
+    gpu_wins: usize = 0,
+    cpu_wins: usize = 0,
+    npu_wins: usize = 0,
+    total_decisions: usize = 0,
+
+    // Latency tracking for learning
+    gpu_latencies: RingBuffer(f64, 100) = .{},
+    cpu_latencies: RingBuffer(f64, 100) = .{},
+    npu_latencies: RingBuffer(f64, 100) = .{},
+
+    // Device availability
+    gpu_available: bool,
+    npu_available: bool,
+
+    const Self = @This();
+
+    pub fn init(allocator: Allocator) Self {
+        return Self{
+            .allocator = allocator,
+            .thresholds = .{},
+            .gpu_available = detectGPU(),
+            .npu_available = detectNPU(),
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        _ = self;
+        // Nothing to free currently
+    }
+
+    /// Select optimal device for given workload
+    pub fn selectDevice(
+        self: *Self,
+        batch_size: usize,
+        sequence_length: usize,
+        embedding_dim: usize,
+    ) Device {
+        const total_elements = batch_size * sequence_length * embedding_dim;
+
+        // Record decision for stats
+        self.total_decisions += 1;
+
+        // Check NPU first (best for large, predictable batches)
+        if (self.npu_available and self.shouldUseNPU(batch_size, total_elements)) {
+            return .npu;
+        }
+
+        // Check GPU
+        if (self.gpu_available and self.shouldUseGPU(batch_size, sequence_length, total_elements)) {
+            return .gpu;
+        }
+
+        // Default to CPU
+        return .cpu;
+    }
+
+    /// Quick selection for common case (inference with known batch)
+    pub fn selectForInference(self: *Self, batch_size: usize, n_ctx: usize) Device {
+        // Typical embedding dim for modern LLMs
+        const typical_dim: usize = 4096;
+        return self.selectDevice(batch_size, n_ctx, typical_dim);
+    }
+
+    /// Record actual latency for learning
+    pub fn recordLatency(self: *Self, device: Device, latency_ms: f64) void {
+        switch (device) {
+            .gpu => self.gpu_latencies.push(latency_ms),
+            .cpu => self.cpu_latencies.push(latency_ms),
+            .npu => self.npu_latencies.push(latency_ms),
+        }
+
+        // Update win counters based on recent performance
+        if (self.thresholds.enable_learning) {
+            self.updateWinCounters(device);
+        }
+    }
+
+    /// Get statistics
+    pub fn getStats(self: *const Self) Stats {
+        return .{
+            .total_decisions = self.total_decisions,
+            .gpu_wins = self.gpu_wins,
+            .cpu_wins = self.cpu_wins,
+            .npu_wins = self.npu_wins,
+            .gpu_avg_latency = self.gpu_latencies.average(),
+            .cpu_avg_latency = self.cpu_latencies.average(),
+            .npu_avg_latency = self.npu_latencies.average(),
+            .gpu_available = self.gpu_available,
+            .npu_available = self.npu_available,
+        };
+    }
+
+    pub const Stats = struct {
+        total_decisions: usize,
+        gpu_wins: usize,
+        cpu_wins: usize,
+        npu_wins: usize,
+        gpu_avg_latency: ?f64,
+        cpu_avg_latency: ?f64,
+        npu_avg_latency: ?f64,
+        gpu_available: bool,
+        npu_available: bool,
+
+        pub fn format(
+            self: Stats,
+            comptime fmt: []const u8,
+            options: std.fmt.FormatOptions,
+            writer: anytype,
+        ) !void {
+            _ = fmt;
+            _ = options;
+            try writer.print(
+                "GpuPolicy Stats:\n" ++
+                    "  Decisions: {}\n" ++
+                    "  GPU wins: {} ({d:.1}%)\n" ++
+                    "  CPU wins: {} ({d:.1}%)\n" ++
+                    "  NPU wins: {} ({d:.1}%)\n" ++
+                    "  GPU available: {}, avg latency: {?d:.2}ms\n" ++
+                    "  NPU available: {}, avg latency: {?d:.2}ms\n",
+                .{
+                    self.total_decisions,
+                    self.gpu_wins,
+                    if (self.total_decisions > 0) @as(f64, @floatFromInt(self.gpu_wins)) / @as(f64, @floatFromInt(self.total_decisions)) * 100 else 0,
+                    self.cpu_wins,
+                    if (self.total_decisions > 0) @as(f64, @floatFromInt(self.cpu_wins)) / @as(f64, @floatFromInt(self.total_decisions)) * 100 else 0,
+                    self.npu_wins,
+                    if (self.total_decisions > 0) @as(f64, @floatFromInt(self.npu_wins)) / @as(f64, @floatFromInt(self.total_decisions)) * 100 else 0,
+                    self.gpu_available,
+                    self.gpu_avg_latency,
+                    self.npu_available,
+                    self.npu_avg_latency,
+                },
+            );
+        }
+    };
+
+    // =========================================================================
+    // Private helpers
+    // =========================================================================
+
+    fn shouldUseGPU(self: *const Self, batch_size: usize, seq_len: usize, total_elements: usize) bool {
+        const t = self.thresholds;
+
+        // Check minimum thresholds
+        if (batch_size < t.gpu_min_batch) return false;
+        if (seq_len < t.gpu_min_tokens) return false;
+        if (total_elements < t.gpu_min_elements) return false;
+
+        return true;
+    }
+
+    fn shouldUseNPU(self: *const Self, batch_size: usize, total_elements: usize) bool {
+        const t = self.thresholds;
+
+        if (batch_size < t.npu_min_batch) return false;
+
+        // NPU prefers power of 2 batch sizes
+        if (t.npu_prefer_pow2 and !isPowerOf2(batch_size)) return false;
+
+        // NPU needs significant workload
+        if (total_elements < t.gpu_min_elements * 2) return false;
+
+        return true;
+    }
+
+    fn updateWinCounters(self: *Self, winner: Device) void {
+        switch (winner) {
+            .gpu => self.gpu_wins += 1,
+            .cpu => self.cpu_wins += 1,
+            .npu => self.npu_wins += 1,
+        }
+
+        // Adaptive threshold adjustment (simple version)
+        // If GPU is winning too much at low batch sizes, lower threshold
+        // If CPU is winning at high batch sizes, raise threshold
+        if (self.total_decisions > 100 and self.total_decisions % 50 == 0) {
+            self.adjustThresholds();
+        }
+    }
+
+    fn adjustThresholds(self: *Self) void {
+        const gpu_rate = @as(f64, @floatFromInt(self.gpu_wins)) / @as(f64, @floatFromInt(self.total_decisions));
+        const cpu_rate = @as(f64, @floatFromInt(self.cpu_wins)) / @as(f64, @floatFromInt(self.total_decisions));
+
+        // If GPU winning >80%, maybe threshold is too high
+        if (gpu_rate > 0.8 and self.thresholds.gpu_min_batch > 2) {
+            self.thresholds.gpu_min_batch -= 1;
+            log.debug("Lowered GPU threshold to {}", .{self.thresholds.gpu_min_batch});
+        }
+
+        // If CPU winning >80%, maybe threshold is too low
+        if (cpu_rate > 0.8 and self.thresholds.gpu_min_batch < 32) {
+            self.thresholds.gpu_min_batch += 1;
+            log.debug("Raised GPU threshold to {}", .{self.thresholds.gpu_min_batch});
+        }
+    }
+};
+
+// =============================================================================
+// Device Detection
+// =============================================================================
+
+fn detectGPU() bool {
+    if (comptime builtin.os.tag == .macos) {
+        // macOS: Metal is always available on Apple Silicon and recent Intel Macs
+        return true;
+    } else if (comptime builtin.os.tag == .linux) {
+        // Linux: Check for CUDA or ROCm
+        // For now, assume no GPU on Linux (could probe /dev/nvidia* or /dev/kfd)
+        return false;
+    }
+    return false;
+}
+
+fn detectNPU() bool {
+    if (comptime builtin.os.tag == .macos and builtin.cpu.arch == .aarch64) {
+        // Apple Silicon has Neural Engine
+        return true;
+    }
+    return false;
+}
+
+fn isPowerOf2(n: usize) bool {
+    return n > 0 and (n & (n - 1)) == 0;
+}
+
+// =============================================================================
+// Ring Buffer for Latency Tracking
+// =============================================================================
+
+fn RingBuffer(comptime T: type, comptime capacity: usize) type {
+    return struct {
+        data: [capacity]T = undefined,
+        head: usize = 0,
+        count: usize = 0,
+
+        const Self = @This();
+
+        pub fn push(self: *Self, value: T) void {
+            self.data[self.head] = value;
+            self.head = (self.head + 1) % capacity;
+            if (self.count < capacity) self.count += 1;
+        }
+
+        pub fn average(self: *const Self) ?T {
+            if (self.count == 0) return null;
+
+            var sum: T = 0;
+            for (0..self.count) |i| {
+                sum += self.data[i];
+            }
+            return sum / @as(T, @floatFromInt(self.count));
+        }
+    };
+}
+
+// =============================================================================
+// Global Policy (singleton for convenience)
+// =============================================================================
+
+var g_policy: ?GpuPolicy = null;
+
+pub fn getGlobalPolicy(allocator: Allocator) *GpuPolicy {
+    if (g_policy == null) {
+        g_policy = GpuPolicy.init(allocator);
+    }
+    return &g_policy.?;
+}
